const z2ui5_cl_xml_view = require("abap2UI5/z2ui5_cl_xml_view");
const z2ui5_if_app = require("abap2UI5/z2ui5_if_app");
const z2ui5_if_client = require("abap2UI5/z2ui5_if_client");

class z2ui5_cl_demo_app_121 extends z2ui5_if_app {
  async main(client) {
    let view;
    if (client.check_on_init()) {
      view = z2ui5_cl_xml_view.factory();
      view.shell()
        .page({ title: `abap2UI5`, navbuttonpress: client._event_nav_app_leave(), shownavbutton: client.check_app_prev_stack() })
        .simple_form({ title: `Timer Interval 2000 ms`, editable: true })
        .content(`form`);
      client.view_display(view.stringify());
      client.action.gen({ val: z2ui5_if_client.cs_event.start_timer, t_arg: [client._event(`TIMER_FINISHED`), `2000`] });
      return;
    }
    switch (client.get().EVENT) {
      case `TIMER_FINISHED`:
        client.message_box_display(`Timer finished!`);
        break;
    }
  }
}

module.exports = z2ui5_cl_demo_app_121;
